function subscribe(uint256 tokenId, address newSubscriber, bytes calldata data)
        external
        payable
        onlyIfPoolManagerLocked
        onlyIfApproved(msg.sender, tokenId)
    {
        ISubscriber _subscriber = subscriber[tokenId];

        if (_subscriber != NO_SUBSCRIBER) revert AlreadySubscribed(tokenId, address(_subscriber));
        _setSubscribed(tokenId);

        subscriber[tokenId] = ISubscriber(newSubscriber);

        bool success = _call(newSubscriber, abi.encodeCall(ISubscriber.notifySubscribe, (tokenId, data)));

        if (!success) {
            newSubscriber.bubbleUpAndRevertWith(ISubscriber.notifySubscribe.selector, SubscriptionReverted.selector);
        }

        emit Subscription(tokenId, newSubscriber);
    }

function state(uint256 proposalId) public view virtual override returns (ProposalState) {
    ProposalState currentState = super.state(proposalId);

    if (currentState != ProposalState.Queued) {
        return currentState;
    }

    bytes32 queueId = _timelockIds[proposalId];
    if (_timelock.isOperationPending(queueId)) {
        return ProposalState.Queued;
    } else if (_timelock.isOperationDone(queueId)) {
        // This can happen if the proposal is executed directly on the timelock.
        return ProposalState.Executed;
    } else {
        // This can happen if the proposal is canceled directly on the timelock.
        return ProposalState.Canceled;
    }
}

fallback() external {
    address facet = _selectorToFacetAndPosition[msg.sig].facetAddress;
    require(facet != address(0), "Diamond: Function does not exist");
    // Execute public function from facet using delegatecall and return any value.
    assembly {
        // copy function selector and any arguments
        calldatacopy(0, 0, calldatasize())
        // execute function call using the facet
        let result := delegatecall(gas(), facet, 0, calldatasize(), 0, 0)
        // get any return value
        returndatacopy(0, 0, returndatasize())
        // return any return value or error back to the caller
        switch result
        case 0 {
            revert(0, returndatasize())
        }
        default {
            return(0, returndatasize())
        }
    }
}

function run() public broadcast returns (address proxy, address implementation) {
    // Run upgrade safety checks.
    _runUpgradeSafetyChecks();

    // Deploy implementation contract with default admin as its initial admin.
    address impl = address(new SablierComptroller({ initialAdmin: DEFAULT_SABLIER_ADMIN }));

    // Deploy proxy without initialization.
    proxy = address(new ERC1967Proxy({ implementation: impl, _data: "" }));

    // Initialize the proxy by populating its initial states.
    _populateInitialStates(proxy);

    // Get implementation address by reading the implementation storage slot of the proxy.
    implementation = _getImplementation(proxy);

    // Verify the initial states of the proxy contract.
    _verifyInitialStates(proxy);
}

function processRun(string memory json, string memory contractName, address latestAddress)
        internal
        view
        returns (address)
    {
        for (uint256 i = 0; vm.keyExistsJson(json, string.concat("$.transactions[", vm.toString(i), "]")); i++) {
            string memory contractNamePath = string.concat("$.transactions[", vm.toString(i), "].contractName");
            if (vm.keyExistsJson(json, contractNamePath)) {
                string memory deployedContractName = json.readString(contractNamePath);
                if (deployedContractName.isEqualTo(contractName)) {
                    latestAddress =
                        json.readAddress(string.concat("$.transactions[", vm.toString(i), "].contractAddress"));
                }
            }
        }

        return latestAddress;
    }

