function validateOfferItem(
    OrderParameters memory orderParameters,
    uint256 offerItemIndex,
    address seaportAddress
) public view returns (ErrorsAndWarnings memory errorsAndWarnings) {
    // First validate the parameters (correct amount, contract, etc)
    errorsAndWarnings = validateOfferItemParameters(
        orderParameters,
        offerItemIndex,
        seaportAddress
    );
    if (errorsAndWarnings.hasErrors()) {
        // Only validate approvals and balances if parameters are valid
        return errorsAndWarnings;
    }

    // Validate approvals and balances for the offer item
    errorsAndWarnings.concat(
        validateOfferItemApprovalAndBalance(
            orderParameters,
            offerItemIndex,
            seaportAddress
        )
    );
}

function getReceivedMessageAt(uint256 index)
        external
        view
        returns (
            bytes32 messageId,
            uint64 sourceChainSelector,
            address sender,
            string memory message,
            address token,
            uint256 amount
        )
    {
        if (index >= receivedMessages.length) {
            revert IndexOutOfBound(index, receivedMessages.length - 1);
        }
        messageId = receivedMessages[index];
        Message memory detail = messageDetail[messageId];
        return (messageId, detail.sourceChainSelector, detail.sender, detail.message, detail.token, detail.amount);
    }

function initialize(
