}

function wrap(
    uint256 amount,
    address recipient
) external onlyAlchemist returns (uint256) {
    // Transfer the underlying tokens from the message sender.
    SafeERC20.safeTransferFrom(underlyingToken, msg.sender, address(this), amount);
    SafeERC20.safeApprove(underlyingToken, token, amount);

    uint256 balanceBefore = IERC20(token).balanceOf(address(this));

    // Vesper deposit does not accept a recipient argument and does not return mint amount
    IVesperPool(token).deposit(amount);

    uint256 balanceAfter = IERC20(token).balanceOf(address(this));

    uint256 minted = balanceAfter - balanceBefore;

    // We must transfer to recipient after and use IERC20.balanceOf() for amount
    SafeERC20.safeTransfer(token, recipient, minted);

    return minted;
}

function withdrawEther(
  uint256 amount,
  address payable recipient,
  uint256 minimumActionGas,
  bytes calldata userSignature,
  bytes calldata dharmaSignature
) external returns (bool ok) {
  // Ensure caller and/or supplied signatures are valid and increment nonce.
  _validateActionAndIncrementNonce(
    ActionType.ETHWithdrawal,
    abi.encode(amount, recipient),
    minimumActionGas,
    userSignature,
    dharmaSignature
  );

  // Ensure that a non-zero amount of Ether has been supplied.
  require(amount > 0, "Must supply a non-zero amount of Ether.");

  // Ensure that a non-zero recipient has been supplied.
  require(recipient != address(0), "No recipient supplied.");

  // Attempt to transfer Ether to the recipient and emit an appropriate event.
  ok = _transferETH(recipient, amount);
}

function initiateUpgrade(
  address controller,
  address beacon,
  address implementation,
  uint256 extraTime
) external onlyOwner {
  require(controller != address(0), "Must specify a controller address.");

  require(beacon != address(0), "Must specify a beacon address.");

  // Ensure that the implementaton contract is not the null address.
  require(
    implementation != address(0),
    "Implementation cannot be the null address."
  );

  // Ensure that the implementation contract has code via extcodesize.
  uint256 size;
  assembly {
    size := extcodesize(implementation)
  }
  require(size > 0, "Implementation must have contract code.");

  // Set the timelock and emit a `TimelockInitiated` event.
  _setTimelock(
    this.upgrade.selector,
    abi.encode(controller, beacon, implementation),
    extraTime
  );
}

function getVotesAndDelegateAtRoundStart(address _account, uint256 _round)
        public
        view
        virtual
        returns (uint256 votes, address delegateAddress)
    {
        BondingCheckpoint storage bond = getBondingCheckpointAt(_account, _round);

        delegateAddress = bond.delegateAddress;

        if (bond.bondedAmount == 0) {
            votes = 0;
        } else if (isRegisteredTranscoder(_account, bond)) {
            // Address is a registered transcoder so we use its delegated amount. This includes self and delegated stake
            // as well as any accrued rewards, even unclaimed ones
            votes = bond.delegatedAmount;
        } else {
            // Address is NOT a registered transcoder so we calculate its cumulative stake for the voting power
            votes = delegatorVotesAtRoundStart(bond, _round);
        }
    }

function transferAllowed(
    address cToken,
    address src,
    address dst,
    uint transferTokens
) external override returns (uint) {
    // Pausing is a very serious situation - we revert to sound the alarms
    require(!transferGuardianPaused, "transfer is paused");

    // Currently the only consideration is whether or not
    //  the src is allowed to redeem this many tokens
    uint allowed = redeemAllowedInternal(cToken, src, transferTokens);
    if (allowed != uint(Error.NO_ERROR)) {
        return allowed;
    }

    // Keep the flywheel moving
    updateCompSupplyIndex(cToken);
    distributeSupplierComp(cToken, src);
    distributeSupplierComp(cToken, dst);

    return uint(Error.NO_ERROR);
}

function _setContributorCompSpeed(address contributor, uint compSpeed) public {
    require(adminOrInitializing(), "only admin can set comp speed");

    // note that COMP speed could be set to 0 to halt liquidity rewards for a contributor
    updateContributorRewards(contributor);
    if (compSpeed == 0) {
        // release storage
        delete lastContributorBlock[contributor];
    } else {
        lastContributorBlock[contributor] = getBlockNumber();
    }
    compContributorSpeeds[contributor] = compSpeed;

    emit ContributorCompSpeedUpdated(contributor, compSpeed);
}

function getCompBalanceMetadataExt(
    Comp comp,
    ComptrollerLensInterface comptroller,
    address account
) external returns (CompBalanceMetadataExt memory) {
    uint balance = comp.balanceOf(account);
    comptroller.claimComp(account);
    uint newBalance = comp.balanceOf(account);
    uint accrued = comptroller.compAccrued(account);
    uint total = add(accrued, newBalance, "sum comp total");
    uint allocated = sub(total, balance, "sub allocated");

    emit lodeMetaData(balance, allocated);

    return
        CompBalanceMetadataExt({
            balance: balance,
            votes: uint256(comp.getCurrentVotes(account)),
            delegate: comp.delegates(account),
            allocated: allocated
        });
}

function _validateNewAdmin(Call calldata _call) private view {
    address newChainAdmin = abi.decode(_call.data[4:], (address));

    bytes32 implementationCodeHash = newChainAdmin.codehash;

    if (!allowedAdminImplementations[implementationCodeHash]) {
        revert UnallowedImplementation(implementationCodeHash);
    }

    // Since the implementation is known to be correct (from the checks above), we
    // can safely trust the returned value from the call below
    if (!IChainAdmin(newChainAdmin).isRestrictionActive(address(this))) {
        revert RemovingPermanentRestriction();
    }
}

function changeFeeParams(FeeParams calldata _newFeeParams) external onlyAdminOrChainTypeManager onlyL1 {
    // Double checking that the new fee params are valid, i.e.
    // the maximal pubdata per batch is not less than the maximal pubdata per priority transaction.
    if (_newFeeParams.maxPubdataPerBatch < _newFeeParams.priorityTxMaxPubdata) {
        revert PriorityTxPubdataExceedsMaxPubDataPerBatch();
    }

    FeeParams memory oldFeeParams = s.feeParams;

    // we cannot change pubdata pricing mode
    if (_newFeeParams.pubdataPricingMode != oldFeeParams.pubdataPricingMode) {
        revert InvalidPubdataPricingMode();
    }

    s.feeParams = _newFeeParams;

    emit NewFeeParams(oldFeeParams, _newFeeParams);
}

function _getValidatorAttributes(Validator storage validator) private view returns (ValidatorAttr memory) {
    uint32 currentActiveCommit;

    if (block.number >= validatorsCommitBlock) {
        currentActiveCommit = validatorsCommit;
    } else {
        currentActiveCommit = validatorsCommit - 1;
    }

    if (currentActiveCommit > validator.lastSnapshotCommit) {
        return validator.latest;
    } else if (currentActiveCommit > validator.previousSnapshotCommit) {
        return validator.snapshot;
    } else {
        return validator.previousSnapshot;
    }
}

function _performDeployOnAddress(
    bytes32 _bytecodeHash,
    address _newAddress,
    AccountAbstractionVersion _aaVersion,
    bytes calldata _input,
    bool _callConstructor
) internal {
    _ensureBytecodeIsKnown(_bytecodeHash);

    AccountInfo memory newAccountInfo;
    newAccountInfo.supportedAAVersion = _aaVersion;
    // Accounts have keyed sequential nonces by default.
    newAccountInfo.nonceOrdering = AccountNonceOrdering.KeyedSequential;
    _storeAccountInfo(_newAddress, newAccountInfo);

    _constructContract({
        _sender: msg.sender,
        _newAddress: _newAddress,
        _bytecodeHash: _bytecodeHash,
        _input: _input,
        _isSystem: false,
        _callConstructor: _callConstructor
    });
}

function getLastReceivedMessageDetails()
        external
        view
        returns (
            bytes32 messageId,
            uint64 sourceChainSelector,
            address sender,
            string memory message,
            address token,
            uint256 amount
        )
    {
        // Revert if no messages have been received
        if (receivedMessages.length == 0) revert NoMessageReceived();

        // Fetch the last received message ID
        messageId = receivedMessages[receivedMessages.length - 1];

        // Fetch the details of the last received message
        Message memory detail = messageDetail[messageId];

        return (messageId, detail.sourceChainSelector, detail.sender, detail.message, detail.token, detail.amount);
    }

function _approve(RegistrationParams memory params, bytes32 hash) private returns (uint256) {
  AutomationRegistryBaseInterface keeperRegistry = s_config.keeperRegistry;

  // register upkeep
  uint256 upkeepId = keeperRegistry.registerUpkeep(
    params.upkeepContract,
    params.gasLimit,
    params.adminAddress,
    params.checkData,
    params.offchainConfig
  );
  // fund upkeep
  bool success = LINK.transferAndCall(address(keeperRegistry), params.amount, abi.encode(upkeepId));
  if (!success) {
    revert LinkTransferFailed(address(keeperRegistry));
  }

  emit RegistrationApproved(hash, params.name, upkeepId);

  return upkeepId;
}

function getTransmitterInfo(
  address query
) external view returns (bool active, uint8 index, uint96 balance, uint96 lastCollected, address payee) {
  Transmitter memory transmitter = s_transmitters[query];

  uint96 pooledShare = 0;
  if (transmitter.active) {
    uint96 totalDifference = s_hotVars.totalPremium - transmitter.lastCollected;
    pooledShare = totalDifference / uint96(s_transmittersList.length);
  }

  return (
    transmitter.active,
    transmitter.index,
    (transmitter.balance + pooledShare),
    transmitter.lastCollected,
    s_transmitterPayees[query]
  );
}

function withdrawEther(
  uint256 amount,
  address payable recipient,
  uint256 minimumActionGas,
  bytes calldata userSignature,
  bytes calldata dharmaSignature
) external returns (bool ok) {
  // Ensure caller and/or supplied signatures are valid and increment nonce.
  _validateActionAndIncrementNonce(
    ActionType.ETHWithdrawal,
    abi.encode(amount, recipient),
    minimumActionGas,
    userSignature,
    dharmaSignature
  );

  // Ensure that a non-zero amount of Ether has been supplied.
  require(amount > 0, _revertReason(4));

  // Ensure that a non-zero recipient has been supplied.
  require(recipient != address(0), _revertReason(1));

  // Attempt to transfer Ether to the recipient and emit an appropriate event.
  ok = _transferETH(recipient, amount);
}

function initiateTransferControllerOwnership(
  address controller, address newOwner, uint256 extraTime
) external onlyOwner {
  require(controller != address(0), "No controller address provided.");

  require(newOwner != address(0), "No new owner address provided.");

  // Ensure that the new owner has confirmed that it can accept ownership.
  require(
    _willAcceptOwnership[controller][newOwner],
    "New owner must agree to accept ownership of the given controller."
  );

  // Set the timelock and emit a `TimelockInitiated` event.
  _setTimelock(
    this.transferControllerOwnership.selector,
    abi.encode(controller, newOwner),
    extraTime
  );
}

function enter(EbisuAdjustInterestRateFuseEnterData calldata data_) external {
    _requireSupportedSubstrates(data_.zapper, data_.registry);

    uint256 troveId = _getTroveIdOrRevert(data_.zapper);

    IAddressesRegistry registry = IAddressesRegistry(data_.registry);
    IBorrowerOperations registryBorrowerOperations = IBorrowerOperations(address(registry.borrowerOperations()));

    registryBorrowerOperations.adjustTroveInterestRate(
        troveId,
        data_.newAnnualInterestRate,
        data_.upperHint,
        data_.lowerHint,
        data_.maxUpfrontFee
    );

    emit EbisuAdjustInterestRateFuseEnter(troveId, data_.newAnnualInterestRate);
}

