  _ESCAPE_HATCH_REGISTRY.setEscapeHatch(account);
}

function getPriorImplementation(
  address controller, address beacon, uint256 index
) external view returns (address priorImplementation, bool rollbackAllowed) {
  // Ensure that there is an implementation address with the given index.
  require(
    _implementations[controller][beacon].length > index,
    "No implementation contract found with the given index."
  );

  // Get information on the specified prior implementation contract.
  PriorImplementation memory implementation = (
    _implementations[controller][beacon][index]
  );

  priorImplementation = implementation.implementation;
  rollbackAllowed = (
    priorImplementation != address(0) && !implementation.rollbackBlocked
  );
}

function comboCalcBbkRct(uint256 cur, uint256 max, uint256 theo) internal pure returns (uint256) {
    if (cur >= max) {
        // If the hourly limit has already been reached, return 0;
        return 0;
    }
    else {
        // Get the available amount
        uint256 available = max.sub(cur);

        if (theo >= available) {
            // If the the theoretical is more than the available, return the available
            return available;
        }
        else {
            // Otherwise, return the theoretical amount
            return theo;
        }
    }
}

constructor(
    address underlying_,
    ComptrollerInterface comptroller_,
    InterestRateModel interestRateModel_,
    uint initialExchangeRateMantissa_,
    string memory name_,
    string memory symbol_,
    uint8 decimals_,
    address payable admin_
) {
    // Creator of the contract is admin during initialization
    admin = payable(msg.sender);

    // Initialize the market
    initialize(
        underlying_,
        comptroller_,
        interestRateModel_,
        initialExchangeRateMantissa_,
        name_,
        symbol_,
        decimals_
    );

    // Set the proper admin now that initialization is done
    admin = admin_;
}

function cancelAccountRecovery(
  address smartWallet, address userSigningKey
) external onlyOwnerOr(Role.CANCELLER) {
  require(smartWallet != address(0), "No smart wallet address provided.");
  require(userSigningKey != address(0), "No user signing key provided.");

  // Expire the timelock for the account recovery in question if one exists.
  _expireTimelock(
    this.recover.selector, abi.encode(smartWallet, userSigningKey)
  );

  // Emit an event to signify that the recovery was cancelled.
  emit RecoveryCancelled(smartWallet, userSigningKey);
}

function perform() external {
    // upgrade implementation
    ProxyAdmin(proxyAdmin).upgrade(
        TransparentUpgradeableProxy(payable(nomineeElectionGovernorProxy)),
        newNomineeElectionGovernorImplementation
    );

    // set the voting delay
    SecurityCouncilNomineeElectionGovernor(payable(nomineeElectionGovernorProxy)).relay(
        nomineeElectionGovernorProxy,
        0,
        abi.encodeCall(GovernorSettingsUpgradeable.setVotingDelay, (votingDelay))
    );

    // set the new constitution hash
    IArbitrumDAOConstitution(constitution).setConstitutionHash(newConstitutionHash);
}

function callWithdraw() private {
    // this balance correctly updates after withdraw
    uint256 challengeTotalRemainingBalance = address(challenge).balance;
    // are there more tokens to empty?
    bool keepRecursing = challengeTotalRemainingBalance > 0;

    if (keepRecursing) {
        // can only withdraw at most our initial balance per withdraw call
        uint256 toWithdraw =
            initialDeposit < challengeTotalRemainingBalance
                ? initialDeposit
                : challengeTotalRemainingBalance;
        challenge.withdraw(toWithdraw);
    }
}

function newKeyRingAndDaiWithdrawal(
  address userSigningKey,
  address smartWallet,
  uint256 amount,
  address recipient,
  uint256 minimumActionGas,
  bytes calldata userSignature,
  bytes calldata dharmaSignature
) external returns (address keyRing, bool withdrawalSuccess) {
  // Deploy and initialize a keyring instance and emit a corresponding event.
  keyRing = _deployNewKeyRing(userSigningKey);

  // Attempt to withdraw Dai from the provided smart wallet.
  withdrawalSuccess = DharmaSmartWalletImplementationV0Interface(
    smartWallet
  ).withdrawDai(
    amount, recipient, minimumActionGas, userSignature, dharmaSignature
  );
}

function newKeyRingAndAdditionalKey(
  address userSigningKey,
  address targetKeyRing,
  address additionalSigningKey,
  bytes calldata signature
) external returns (address keyRing) {
  // Deploy and initialize a keyring if needed and emit a corresponding event.
  keyRing = _deployNewKeyRingIfNeeded(userSigningKey, targetKeyRing);

  // Set the additional key on the newly-deployed keyring.
  DharmaKeyRingImplementationV0Interface(keyRing).takeAdminAction(
    DharmaKeyRingImplementationV0Interface.AdminActionType.AddDualKey,
    uint160(additionalSigningKey),
    signature
  );
}

function newSmartWallet(
  address userSigningKey
) external returns (address wallet) {
  // Get initialization calldata from initialize selector & user signing key.
  bytes memory initializationCalldata = abi.encodeWithSelector(
    _initializer.initialize.selector,
    userSigningKey
  );

  // Initialize and deploy new user smart wallet as an Upgrade Beacon proxy.
  wallet = _deployUpgradeBeaconProxyInstance(initializationCalldata);

  // Emit an event to signal the creation of the new smart wallet.
  emit SmartWalletDeployed(wallet, userSigningKey);
}

function newSmartWalletAndNewUserSigningKey(
  address userSigningKey,
  address targetSmartWallet,
  address newUserSigningKey,
  uint256 minimumActionGas,
  bytes calldata userSignature,
  bytes calldata dharmaSignature
) external returns (address wallet) {
  // Deploy a new smart wallet if needed and emit a corresponding event.
  wallet = _deployNewSmartWalletIfNeeded(userSigningKey, targetSmartWallet);

  // Set the new user signing key on the newly-deployed smart wallet.
  DharmaSmartWalletImplementationV0Interface(wallet).setUserSigningKey(
    newUserSigningKey, minimumActionGas, userSignature, dharmaSignature
  );
}

function setProposal(GovProposal memory res, GovernorAlpha governor, uint proposalId) internal view {
    (
        ,
        address proposer,
        uint eta,
        uint startBlock,
        uint endBlock,
        uint forVotes,
        uint againstVotes,
        bool canceled,
        bool executed
    ) = governor.proposals(proposalId);
    res.proposalId = proposalId;
    res.proposer = proposer;
    res.eta = eta;
    res.startBlock = startBlock;
    res.endBlock = endBlock;
    res.forVotes = forVotes;
    res.againstVotes = againstVotes;
    res.canceled = canceled;
    res.executed = executed;
}

function newKeyRingAndUSDCWithdrawal(
  address userSigningKey,
  address smartWallet,
  uint256 amount,
  address recipient,
  uint256 minimumActionGas,
  bytes calldata userSignature,
  bytes calldata dharmaSignature
) external returns (address keyRing, bool withdrawalSuccess) {
  // Deploy and initialize a keyring instance and emit a corresponding event.
  keyRing = _deployNewKeyRing(userSigningKey);

  // Attempt to withdraw USDC from the provided smart wallet.
  withdrawalSuccess = DharmaSmartWalletImplementationV0Interface(
    smartWallet
  ).withdrawUSDC(
    amount, recipient, minimumActionGas, userSignature, dharmaSignature
  );
}

